// Federations ingest — find-or-create into PocketBase (no upsert in PB).
// Auth handled by the upstream "PB Auth" HTTP node (Custom Auth credential); this node
// reuses that token. FIVB VIS returns JSON when Accept: application/json.

const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const VIS_URL = $('Config').first().json.visUrl || 'https://www.fivb.org/Vis2009/XmlRequest.asmx';
const token = $('PB Auth').first().json.token;
if (!token) {
  throw new Error('No PocketBase token — check the "PocketBase admin" credential on the PB Auth node.');
}

const headers = ($('Webhook').first().json.headers) || {};
const rescrape = String(headers.rescrape || headers.Rescrape || '').toLowerCase() === 'true';

// FIVB VIS JSON shape: { data: [ { code, name, teamName, confederationCode, webSite, ... } ] }
const visJson = $('FIVB VIS GetFederationList').first().json;
let feds = visJson && (Array.isArray(visJson) ? visJson : visJson.data);
if (!feds) feds = [];
if (!Array.isArray(feds)) feds = [feds];

const get = (f, ...keys) => {
  for (const k of keys) {
    const v = f[k];
    if (v != null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};
const normUrl = (u) => {
  u = (u || '').trim();
  if (!u) return '';
  return /^https?:\/\//i.test(u) ? u : 'https://' + u;
};

const pbHeaders = { Authorization: token };
const findByCode = async (code) => {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: PB_URL + '/api/collections/federations/records',
    qs: { filter: "(fivb_code='" + code + "')", perPage: 1 },
    headers: pbHeaders, json: true,
  });
  return (res.items && res.items[0]) || null;
};

let created = 0, updated = 0, failed = 0;
const errors = [];
const now = new Date().toISOString();

for (const f of feds) {
  const code = get(f, 'code');
  if (!code) continue;

  const payload = {
    fivb_code: code,
    name: get(f, 'name'),
    country: get(f, 'teamName'),
    confederation: get(f, 'confederationCode'),
    website_url: normUrl(get(f, 'webSite')),
    president: get(f, 'namePresident'),
    general_secretary: get(f, 'nameGeneralSecretary'),
    email: get(f, 'eMailAddress'),
    phone: get(f, 'phoneNo'),
    source_url: VIS_URL,
    last_scraped: now,
  };

  try {
    const existing = await findByCode(code);
    if (existing) {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: PB_URL + '/api/collections/federations/records/' + existing.id,
        headers: pbHeaders, body: payload, json: true,
      });
      updated++;
    } else {
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: PB_URL + '/api/collections/federations/records',
          headers: pbHeaders, body: Object.assign({ status: 'new' }, payload), json: true,
        });
        created++;
      } catch (e) {
        const again = await findByCode(code);
        if (again) {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: PB_URL + '/api/collections/federations/records/' + again.id,
            headers: pbHeaders, body: payload, json: true,
          });
          updated++;
        } else { throw e; }
      }
    }
  } catch (e) {
    failed++;
    if (errors.length < 10) errors.push({ code, message: (e && e.message) || String(e) });
  }
}

return [{ json: { ok: failed === 0, total: feds.length, created, updated, failed, rescrape, errors } }];
